import React, { useState } from 'react';

const skillsData = [
  { name: 'HTML & CSS',    level: 85, sym: '✕', color: '#7fc5e8' },
  { name: 'JavaScript',   level: 70, sym: '○', color: '#e87b7b' },
  { name: 'React',        level: 60, sym: '□', color: '#e87bce' },
  { name: 'Bootstrap',    level: 75, sym: '△', color: '#7be8b4' },
  { name: 'Tailwind CSS', level: 60, sym: '✕', color: '#7fc5e8' },
  { name: 'Git & GitHub', level: 65, sym: '○', color: '#e87b7b' },
];

const Skills = () => {
  const [hovered, setHovered] = useState(null);

  return (
    <section
      id="Skills"
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
      style={{ background: 'var(--ps-dark, #00052b)' }}
    >
      <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">Skills</h1>

      <div className="w-full max-w-2xl flex flex-col gap-6">
        {skillsData.map((skill, i) => {
          const isHov = hovered === i;
          return (
            <div key={i}>
              <div className="flex justify-between items-center mb-2">
                <span className="flex items-center gap-2 font-bold text-sm text-white">
                  <span style={{ color: skill.color, fontSize: '13px' }}>{skill.sym}</span>
                  {skill.name}
                </span>
                <span
                  className="text-xs font-bold px-2 py-0.5 rounded-full"
                  style={{
                    background: `${skill.color}22`,
                    color: skill.color,
                    border: `1px solid ${skill.color}55`,
                  }}
                >
                  {skill.level}%
                </span>
              </div>

              {/* Track */}
              <div
                className="w-full rounded-full h-3"
                style={{ background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.1)' }}
              >
                <div
                  className="h-3 rounded-full transition-all duration-500"
                  style={{
                    width: `${skill.level}%`,
                    background: isHov
                      ? `linear-gradient(90deg, ${skill.color}, #ffffff44)`
                      : `linear-gradient(90deg, #003791, ${skill.color}cc)`,
                    boxShadow: isHov ? `0 0 8px ${skill.color}99` : 'none',
                    transition: 'background 0.3s, box-shadow 0.3s, width 0.5s',
                  }}
                  onMouseEnter={() => setHovered(i)}
                  onMouseLeave={() => setHovered(null)}
                />
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
};

export default Skills;
